var e=[{id:`L2_1`,type:`dialog`,speaker:`SOLDIER_NPC_REVELA_NULL`,text:{KOREA:`우아악! 저리 꺼져!`,JPN:`うわあ！　近づくんじゃねえ！`,ENG:`Waaaah! Go away!`,TWN:`啊啊！給我滾開！`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`MAN_NPC_REVELA_LEADER`,text:{KOREA:`이 멍청이가! 차를 쏘면 어떡해! 정부군이 모는 군수차량은 비싸다고!`,JPN:`バカ野郎！　車を撃ってどうすんだ！　政府軍の軍用車両は高いんだぞ！`,ENG:`You fool! Don't shoot at the car! The government's military vehicles are expensive!`,TWN:`蠢蛋！你開槍射車子幹嘛！政府軍開的補給車很貴欸！`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:{char_id:`MAN_NPC_REVELA_LEADER`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`MAN_NPC_REVELA_LEADER`,text:{KOREA:`크헉!`,JPN:`くはっ！`,ENG:`Ugh!`,TWN:`唔！`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:null,R:{char_id:`MAN_NPC_REVELA_LEADER`,face:`UNIT_IDLE`}}}},{id:`L12_1`,type:`dialog`,speaker:`MAN_NPC_REVELA_LEADER`,text:{KOREA:`뭐야, 제길! 총이 두 동강났잖아!`,JPN:`何だよ、ちくしょう！　銃が真っ二つになったじゃないか！`,ENG:`Drat, it broke my gun in half!`,TWN:`該死！搞什麼？槍斷成兩截了！`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:null,R:{char_id:`MAN_NPC_REVELA_LEADER`,face:`UNIT_IDLE`}}}},{id:`L14_1`,type:`dialog`,speaker:`MAN_NPC_REVELA_LEADER`,text:{KOREA:`크…… 크으윽!`,JPN:`くっ……くそっ！`,ENG:`Grr... Grrr!`,TWN:`嗚……嗚嗚！`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:null,R:{char_id:`MAN_NPC_REVELA_LEADER`,face:`UNIT_IDLE`}}}},{id:`L16_1`,type:`dialog`,speaker:`LUCID_BARCODE_NULL_NULL`,text:{KOREA:`안돼! 죽이지 마!`,JPN:`ダメ！　殺さないで！`,ENG:`No! Don't kill him!`,TWN:`不可以！別殺他！`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`CORRUPTED_NPC_LUCID_PET`,text:{KOREA:`크르르……`,JPN:`ガルル……`,ENG:`Grr...`,TWN:`呼嚕嚕……`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`MAN_NPC_REVELA_LEADER`,text:{KOREA:`뭐야. 침식체가…… 물러선다고?`,JPN:`なんだ？　侵食体が……退いてる？`,ENG:`What the...? The C.O... It's moving away.`,TWN:`怎麼會？侵蝕體……離開了？`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`REVELA_NPC_NULL_NULL`,text:{KOREA:`……저걸 봐. 저 여자애 주위로 침식체가 모이고 있어.`,JPN:`……あれを見ろ。あの女の周りに侵食体が集まっている。`,ENG:`Look, the C.O.s are gathering around that girl.`,TWN:`……你們看！侵蝕體都跑到那女的旁邊了！`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`REVELB_NPC_NULL_NULL`,text:{KOREA:`설마…… 저거, 그림자인가?`,JPN:`まさか……あれは、シャドウなのか？`,ENG:`Oh, no... Is that... a Shadow?`,TWN:`她該不會……是暗影吧？`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`REVELA_NPC_NULL_NULL`,text:{KOREA:`그, 그림자? 태스크포스도 쩔쩔맨다는 그거?`,JPN:`シャ、シャドウ？　タスクフォースカンパニーも手こずるって噂の？`,ENG:`Sh-Shadow? You mean one of those monsters that even the TASKFORCE companies have a hard time dealing with?`,TWN:`暗影？那個連特遣勢力看到都怕的暗影嗎？`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`REVELB_NPC_NULL_NULL`,text:{KOREA:`그, 그래! 그거! 어쩐지 요새 사람들을 공격하는 카운터 얘기가 돌곤 했어!`,JPN:`そ、そう！　それだ！　どうりで最近人を襲うカウンターの噂が出回っていたのか！`,ENG:`Y-yeah, that! I've recently heard about a Counter who attacks people!`,TWN:`肯定沒錯！難怪最近聽說發生很多攻擊事件！`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`REVELA_NPC_NULL_NULL`,text:{KOREA:`침식체를 부리다니…… 저건 역시 그림자였던 거야!`,JPN:`侵食体を操るとは……やっぱりあれはシャドウだったんだ！`,ENG:`Controlling C.O.s... That's got to be a Shadow!`,TWN:`竟然可以控制侵蝕體……她一定是暗影沒錯啦！`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`REVELB_NPC_NULL_NULL`,text:{KOREA:`그런 거였어. 어, 어쩐지 오늘 운이 좋다 했다고! 도망쳐!`,JPN:`そういうことか。な、なんだか今日は運がいいと思ったらこれか！　逃げろ！`,ENG:`I knew it. T-today was too good to be true! Run!`,TWN:`可惡！我還想說今天運氣怎麼這麼好！快逃！`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:{char_id:`LUCID_BARCODE_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L31_1`,type:`dialog`,speaker:`MAN_NPC_REVELA_LEADER`,text:{KOREA:`저, 저것들이 자기들끼리!`,JPN:`おい、お前ら勝手に逃げるな！`,ENG:`Th-those cowards!`,TWN:`他們竟然給我自己跑掉！`},stage:{bg:`COUNTRYROAD`,slots:{L:null,C:{char_id:`MAN_NPC_REVELA_LEADER`,face:`UNIT_IDLE`},R:null}}}];export{e as default};